ee:message.ee:set-payload:
%dw 2.0
output application/json
var errorRegistry = {
                        "COMMUNICATION": {
                            status: 503,
                            message: "Communication Error - Failed to communicate with Salesforce",
                            details: "An error occurred while communicating with the Salesforce service"
                        },
                        "CONNECTIVITY": {
                            status: 503,
                            message: "Connectivity Error - Unable to establish connection to Salesforce",
                            details: "The connection to Salesforce could not be established or was lost"
                        },
                        "INSUFFICIENT_PERMISSIONS": {
                            status: 403,
                            message: "Insufficient Permissions - The user does not have required Salesforce permissions",
                            details: "The authenticated user lacks the necessary permissions to perform this operation in Salesforce"
                        },
                        "INVALID_INPUT": {
                            status: 400,
                            message: "Invalid Input - The data provided does not meet Salesforce requirements",
                            details: "The request contains invalid or malformed data that cannot be processed by Salesforce"
                        },
                        "INVALID_RESPONSE": {
                            status: 502,
                            message: "Invalid Response - Salesforce returned an unexpected or malformed response",
                            details: "The response received from Salesforce could not be parsed or is in an unexpected format"
                        },
                        "LIMIT_EXCEEDED": {
                            status: 429,
                            message: "Limit Exceeded - Salesforce API limit or governor limit has been exceeded",
                            details: "The request has exceeded the allowed Salesforce API or governor limits, please retry after some time"
                        },
                        "MUTUAL_AUTHENTICATION_FAILED": {
                            status: 401,
                            message: "Mutual Authentication Failed - Salesforce mutual TLS authentication could not be completed",
                            details: "The mutual authentication handshake with Salesforce failed, please verify certificates and credentials"
                        },
                        "NOT_FOUND": {
                            status: 404,
                            message: "Not Found - The requested Salesforce record or resource does not exist",
                            details: "The specified Salesforce resource, record or object could not be found"
                        },
                        "OPERATION_NOT_SUPPORTED": {
                            status: 405,
                            message: "Operation Not Supported - The requested operation is not supported in Salesforce",
                            details: "The attempted operation is not allowed or supported for this Salesforce resource"
                        },
                        "RETRY_EXHAUSTED": {
                            status: 503,
                            message: "Retry Exhausted - Maximum retry attempts to Salesforce have been exceeded",
                            details: "All retry attempts to connect or interact with Salesforce have been exhausted"
                        },
                        "TIMEOUT": {
                            status: 504,
                            message: "Timeout - The Salesforce request did not complete within the allowed time",
                            details: "The connection or operation to Salesforce timed out before a response was received"
                        },
                        "UNAVAILABLE": {
                            status: 503,
                            message: "Unavailable - The Salesforce service is temporarily unavailable",
                            details: "Salesforce is currently unavailable, please try again later"
                        }
                    }

var identifier = error.errorType.identifier
var mapped     = errorRegistry[identifier]
---
 {
	"statusCode": mapped.status  default 500,
	"message": mapped.message default error.description,
	"error": "SALESFORCE_" ++ identifier,
	"timestamp": now(),
	"correlationId": correlationId,
	"details": error.detailedDescription default mapped.details default "An unexpected Salesforce error occurred"
 }
